def construct(N: int) -> list[tuple[int, int]]:
    """Cubic residues union with offset set {1}."""
    if N < 3:
        return []

    # Compute cubic residues mod N
    cr = set()
    for x in range(N):
        cr.add((x * x * x) % N)

    edges = set()
    for i in range(N):
        for j in range(i + 1, N):
            diff = (j - i) % N
            # Cubic residue OR offset of 1
            if (diff in cr and diff != 0) or diff == 1:
                edges.add((i, j))

    return list(edges)

def construct(N: int) -> list[tuple[int, int]]:
    """Strong product of C_3 and ring: vertices are (i,j), i in {0,1,2}, j in {0..N/3-1}."""
    if N % 3 != 0:
        return []

    n = N // 3
    edges = set()

    # Vertices: (i, j) -> vertex ID i*n + j for i in {0,1,2}, j in {0..n-1}
    # Strong product: adjacent if differ by 1 in either coordinate (or both)

    for i in range(3):
        for j in range(n):
            v = i * n + j

            # Ring edges: within same i, adjacent j
            j_next = (j + 1) % n
            u = i * n + j_next
            if v < u:
                edges.add((v, u))

            # Between layers: different i
            for i2 in range(i + 1, 3):
                u = i2 * n + j
                edges.add((v, u))

    return list(edges)

def construct(N: int) -> list[tuple[int, int]]:
    """Cartesian product C_3 □ C_n: vertices are (i,j), i in {0,1,2}, j in {0..N/3-1}."""
    if N % 3 != 0:
        return []

    n = N // 3
    edges = set()

    # Vertices: (i, j) -> vertex ID i*n + j for i in {0,1,2}, j in {0..n-1}
    # Cartesian product edges:
    # 1. Within same j, adjacent i (forms C_3 on i coordinate)
    # 2. Within same i, adjacent j (forms C_n on j coordinate)

    for i in range(3):
        for j in range(n):
            v = i * n + j

            # C_3 structure: connect adjacent i (ring)
            i_next = (i + 1) % 3
            u = i_next * n + j
            if v < u:
                edges.add((v, u))

            # C_n structure: connect adjacent j (ring)
            j_next = (j + 1) % n
            u = i * n + j_next
            if v < u:
                edges.add((v, u))

    return list(edges)

def construct(N: int) -> list[tuple[int, int]]:
    """Union of cubic and quadratic residues mod N."""
    if N < 3:
        return []

    # Compute cubic and quadratic residues mod N
    cr = set()
    qr = set()
    for x in range(N):
        cr.add((x * x * x) % N)
        qr.add((x * x) % N)

    edges = set()
    for i in range(N):
        for j in range(i + 1, N):
            diff = (j - i) % N
            if diff != 0 and (diff in cr or diff in qr):
                edges.add((i, j))

    return list(edges)

